    bit = n.bit_length() - 1

    while bit >= 0:
        # Fast doubling: compute F(2k) and F(2k+1) from F(k) and F(k+1)
        c = a * ((b << 1) - a)
        d = a * a + b * b
        if (n >> bit) & 1:
            a, b = d, c + d
