        two_b_minus_a = (b << 1) - a
        c = a * two_b_minus_a
        d = a * a + b * b
        if (n >> bit) & 1:
            a, b = d, c + d
        else:
            a, b = c, d
        bit -= 1

    return a

def fibonacci(n):
    if n < 0:
        raise ValueError("n must be non-negative")
    if n <= 1:
        return n

    a, b = 0, 1
    for bit in range(n.bit_length() - 1, -1, -1):
        # Fast doubling identities:
        # F(2k)   = F(k) * [2*F(k+1) - F(k)]
        # F(2k+1) = F(k)^2 + F(k+1)^2
        t = a * ((b << 1) - a)
        u = a * a + b * b
        if (n >> bit) & 1:
            a, b = u, t + u
        else:
            a, b = t, u

    return a
